export const presentationMarkup = "<div id=\"stage\">\n  <div class=\"canvas\" id=\"canvas\">\n\n    <!-- SLIDE 1 -->\n    <section class=\"slide s1\" data-slide=\"1\">\n      <div class=\"kicker\">Cellular Neuroscience</div>\n      <h1>G-Proteins and Their Role in Cellular Signal Transduction</h1>\n      <div class=\"question\" id=\"s1-question\">\n        <span class=\"highlight\"></span>\n        How do G-proteins convert receptor activation into a cellular response?\n      </div>\n      <div class=\"subtitle\" id=\"s1-sub\"></div>\n      <div class=\"rule\" id=\"s1-rule\"></div>\n      <div class=\"meta\">Based on Purves, <em>Neuroscience</em> · Chapter on Signal Transduction</div>\n      <div class=\"notes\">\n        <button class=\"notes-toggle\" data-notes-toggle=\"\">Hide notes</button>\n        <div class=\"label\">Speaker notes</div>\n        <div class=\"body\">Today we're going to answer one central question: how do G-proteins convert receptor activation into a cellular response? To understand why this question matters, you need to picture one basic problem: cells are separated from the outside world by a membrane. When a chemical signal arrives from outside, the cell needs machinery to detect it and translate it into something meaningful on the inside. G-proteins are one of the key tools evolution found to solve this problem. And here's the most important thing to understand from the start: G-proteins are not the neurotransmitter, and they are not the final cellular effect. They are the coupling machinery in between.</div>\n      </div>\n    </section>\n\n    <!-- SLIDE 2 -->\n    <section class=\"slide s2\" data-slide=\"2\">\n      <div class=\"eyebrow\">02 · Where the story begins</div>\n      <h2>From synaptic communication to postsynaptic receptors</h2>\n      <div class=\"grid\">\n        <div class=\"synapse\">\n          <svg id=\"synapse-svg\" viewBox=\"0 0 600 520\" width=\"100%\" height=\"100%\" preserveAspectRatio=\"xMidYMid meet\">\n            <defs>\n              <radialGradient id=\"terminalGrad\" cx=\"50%\" cy=\"38%\" r=\"65%\">\n                <stop offset=\"0%\" stop-color=\"#f4cdb3\"></stop>\n                <stop offset=\"70%\" stop-color=\"#e8a17a\"></stop>\n                <stop offset=\"100%\" stop-color=\"#c97a5a\"></stop>\n              </radialGradient>\n              <linearGradient id=\"postGrad\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#f8e89a\"></stop>\n                <stop offset=\"100%\" stop-color=\"#e8c95a\"></stop>\n              </linearGradient>\n              <radialGradient id=\"vesicleGrad\" cx=\"40%\" cy=\"38%\" r=\"60%\">\n                <stop offset=\"0%\" stop-color=\"#a3c8e6\"></stop>\n                <stop offset=\"100%\" stop-color=\"#5a8fb8\"></stop>\n              </radialGradient>\n              <radialGradient id=\"haloGrad\" cx=\"50%\" cy=\"50%\" r=\"50%\">\n                <stop offset=\"0%\" stop-color=\"#ffe27a\" stop-opacity=\"0.95\"></stop>\n                <stop offset=\"60%\" stop-color=\"#ffd14a\" stop-opacity=\"0.6\"></stop>\n                <stop offset=\"100%\" stop-color=\"#ffd14a\" stop-opacity=\"0\"></stop>\n              </radialGradient>\n              <linearGradient id=\"bgSky\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#f1f7fb\"></stop>\n                <stop offset=\"100%\" stop-color=\"#e8f0f5\"></stop>\n              </linearGradient>\n            </defs>\n            <!-- background -->\n            <rect x=\"0\" y=\"0\" width=\"600\" height=\"520\" fill=\"url(#bgSky)\"></rect>\n\n            <!-- Presynaptic neuron (teardrop bulb on stalk) -->\n            <g id=\"pre-group\" opacity=\"0\">\n              <!-- outer outline (lighter) -->\n              <path d=\"M 230 0 L 230 80\n                       C 150 110 100 180 110 260\n                       C 120 330 200 360 300 360\n                       C 400 360 480 330 490 260\n                       C 500 180 450 110 370 80\n                       L 370 0 Z\" fill=\"url(#terminalGrad)\" stroke=\"#a85a3a\" stroke-width=\"2\"></path>\n              <!-- inner membrane line -->\n              <path d=\"M 245 30\n                       C 165 90 122 175 132 255\n                       C 142 318 210 345 300 345\n                       C 390 345 458 318 468 255\n                       C 478 175 435 90 355 30\" fill=\"none\" stroke=\"#fff\" stroke-width=\"2\" opacity=\"0.55\"></path>\n            </g>\n\n            <!-- Vesicles inside terminal -->\n            <g id=\"vesicles\" opacity=\"0\">\n              <g class=\"ves\" transform=\"translate(195,170)\"><circle r=\"20\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle><circle cx=\"-5\" cy=\"-3\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"6\" cy=\"2\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"-2\" cy=\"6\" r=\"3\" fill=\"#1a4769\"></circle></g>\n              <g class=\"ves\" transform=\"translate(265,150)\"><circle r=\"20\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle><circle cx=\"-5\" cy=\"-3\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"6\" cy=\"2\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"-2\" cy=\"6\" r=\"3\" fill=\"#1a4769\"></circle></g>\n              <g class=\"ves\" transform=\"translate(345,158)\"><circle r=\"20\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle><circle cx=\"-5\" cy=\"-3\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"6\" cy=\"2\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"-2\" cy=\"6\" r=\"3\" fill=\"#1a4769\"></circle></g>\n              <g class=\"ves\" transform=\"translate(415,180)\"><circle r=\"20\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle><circle cx=\"-5\" cy=\"-3\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"6\" cy=\"2\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"-2\" cy=\"6\" r=\"3\" fill=\"#1a4769\"></circle></g>\n              <g class=\"ves\" transform=\"translate(225,235)\"><circle r=\"20\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle><circle cx=\"-5\" cy=\"-3\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"6\" cy=\"2\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"-2\" cy=\"6\" r=\"3\" fill=\"#1a4769\"></circle></g>\n              <g class=\"ves\" transform=\"translate(305,228)\"><circle r=\"20\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle><circle cx=\"-5\" cy=\"-3\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"6\" cy=\"2\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"-2\" cy=\"6\" r=\"3\" fill=\"#1a4769\"></circle></g>\n              <g class=\"ves\" transform=\"translate(385,238)\"><circle r=\"20\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle><circle cx=\"-5\" cy=\"-3\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"6\" cy=\"2\" r=\"3\" fill=\"#1a4769\"></circle><circle cx=\"-2\" cy=\"6\" r=\"3\" fill=\"#1a4769\"></circle></g>\n              <!-- docked vesicles at base -->\n              <g class=\"ves docked\" transform=\"translate(245,305)\"><circle r=\"18\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle></g>\n              <g class=\"ves docked\" transform=\"translate(310,305)\"><circle r=\"18\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle></g>\n              <g class=\"ves docked\" transform=\"translate(370,305)\"><circle r=\"18\" fill=\"url(#vesicleGrad)\" stroke=\"#3a6f95\" stroke-width=\"1\"></circle></g>\n            </g>\n\n            <!-- Synaptic cleft label -->\n            <g id=\"cleft-label\" opacity=\"0\"><rect x=\"228\" y=\"352\" width=\"144\" height=\"22\" rx=\"5\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"0.8\" opacity=\"0.92\"></rect><text x=\"300\" y=\"367\" text-anchor=\"middle\" font-size=\"11\" fill=\"#1c2620\" letter-spacing=\"2\" font-weight=\"700\">SYNAPTIC CLEFT</text></g>\n\n            <!-- Postsynaptic membrane (yellow band with green ridge on top) -->\n            <g id=\"post-group\" opacity=\"0\">\n              <!-- top ridge: green band shaped to receive terminal -->\n              <path d=\"M 0 380\n                       C 80 360 140 358 200 372\n                       C 240 382 270 380 300 378\n                       C 330 376 360 380 400 372\n                       C 460 358 520 360 600 380\n                       L 600 410 L 0 410 Z\" fill=\"#9fc78a\" stroke=\"#5a8a45\" stroke-width=\"1.5\"></path>\n              <!-- yellow body -->\n              <path d=\"M 0 408 L 600 408 L 600 520 L 0 520 Z\" fill=\"url(#postGrad)\" stroke=\"#c9a13a\" stroke-width=\"1.5\"></path>\n            </g>\n\n            <!-- Receptors embedded in membrane (T-shape pegs) -->\n            <g id=\"receptors\">\n              <g class=\"rcpt\" transform=\"translate(245,395)\">\n                <rect x=\"-9\" y=\"-12\" width=\"18\" height=\"34\" rx=\"3\" fill=\"#7a5fa8\" stroke=\"#3a2570\" stroke-width=\"1.5\"></rect>\n                <rect x=\"-14\" y=\"-16\" width=\"28\" height=\"10\" rx=\"3\" fill=\"#9a7fc8\" stroke=\"#3a2570\" stroke-width=\"1.5\"></rect>\n              </g>\n              <g class=\"rcpt\" transform=\"translate(310,395)\">\n                <rect x=\"-9\" y=\"-12\" width=\"18\" height=\"34\" rx=\"3\" fill=\"#7a5fa8\" stroke=\"#3a2570\" stroke-width=\"1.5\"></rect>\n                <rect x=\"-14\" y=\"-16\" width=\"28\" height=\"10\" rx=\"3\" fill=\"#9a7fc8\" stroke=\"#3a2570\" stroke-width=\"1.5\"></rect>\n              </g>\n              <g class=\"rcpt\" transform=\"translate(370,395)\">\n                <rect x=\"-9\" y=\"-12\" width=\"18\" height=\"34\" rx=\"3\" fill=\"#7a5fa8\" stroke=\"#3a2570\" stroke-width=\"1.5\"></rect>\n                <rect x=\"-14\" y=\"-16\" width=\"28\" height=\"10\" rx=\"3\" fill=\"#9a7fc8\" stroke=\"#3a2570\" stroke-width=\"1.5\"></rect>\n              </g>\n            </g>\n\n            <!-- Receptor activation halos -->\n            <g id=\"halos\">\n              <circle class=\"halo\" cx=\"245\" cy=\"395\" r=\"0\" fill=\"url(#haloGrad)\"></circle>\n              <circle class=\"halo\" cx=\"310\" cy=\"395\" r=\"0\" fill=\"url(#haloGrad)\"></circle>\n              <circle class=\"halo\" cx=\"370\" cy=\"395\" r=\"0\" fill=\"url(#haloGrad)\"></circle>\n            </g>\n\n            <!-- Neurotransmitter dots (small blue) released into cleft -->\n            <g id=\"nt-dots\"></g>\n\n            <!-- Effector molecules (red dots emerging from inside cell) -->\n            <g id=\"effectors\">\n              <circle class=\"eff\" cx=\"245\" cy=\"455\" r=\"0\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.8\"></circle>\n              <circle class=\"eff\" cx=\"310\" cy=\"465\" r=\"0\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.8\"></circle>\n              <circle class=\"eff\" cx=\"395\" cy=\"450\" r=\"0\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.8\"></circle>\n              <circle class=\"eff\" cx=\"425\" cy=\"478\" r=\"0\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.8\"></circle>\n            </g>\n\n            <!-- Cellular response marker -->\n            <g id=\"cell-response\" opacity=\"0\">\n              <circle class=\"response-wave\" cx=\"330\" cy=\"462\" r=\"28\" fill=\"none\" stroke=\"#3d7a52\" stroke-width=\"2\" opacity=\"0.35\"></circle>\n              <circle class=\"response-wave\" cx=\"330\" cy=\"462\" r=\"44\" fill=\"none\" stroke=\"#3d7a52\" stroke-width=\"1.5\" opacity=\"0.22\"></circle>\n              <rect x=\"255\" y=\"492\" width=\"150\" height=\"22\" rx=\"5\" fill=\"#fff\" stroke=\"#3d7a52\" stroke-width=\"1\" opacity=\"0.94\"></rect>\n              <text x=\"330\" y=\"507\" text-anchor=\"middle\" font-size=\"11\" fill=\"#1c2620\" font-weight=\"700\">Cellular response</text>\n            </g>\n\n            <!-- Callout labels -->\n            <g id=\"callouts\" font-family=\"Inter, sans-serif\">\n              <!-- presynaptic neuron -->\n              <g id=\"co-pre\" opacity=\"0\">\n                <line x1=\"300\" y1=\"180\" x2=\"500\" y2=\"60\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n                <circle cx=\"300\" cy=\"180\" r=\"2.5\" fill=\"#3a4640\"></circle>\n                <rect x=\"500\" y=\"44\" width=\"98\" height=\"32\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <text x=\"549\" y=\"58\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"700\" fill=\"#1c2620\">Presynaptic</text>\n                <text x=\"549\" y=\"71\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"700\" fill=\"#1c2620\">neuron</text>\n              </g>\n              <!-- neurotransmitter -->\n              <g id=\"co-nt\" opacity=\"0\">\n                <line x1=\"295\" y1=\"365\" x2=\"500\" y2=\"180\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n                <rect x=\"496\" y=\"166\" width=\"100\" height=\"22\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <text x=\"546\" y=\"181\" text-anchor=\"middle\" font-size=\"11\" fill=\"#1c2620\">Neurotransmitter</text>\n              </g>\n              <!-- synaptic cleft -->\n              <g id=\"co-cleft\" opacity=\"0\">\n                <line x1=\"540\" y1=\"270\" x2=\"350\" y2=\"378\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n                <rect x=\"496\" y=\"256\" width=\"100\" height=\"22\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <text x=\"546\" y=\"271\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"700\" fill=\"#1c2620\">Synaptic cleft</text>\n              </g>\n              <!-- postsynaptic membrane -->\n              <g id=\"co-post\" opacity=\"0\">\n                <line x1=\"540\" y1=\"358\" x2=\"500\" y2=\"395\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n                <rect x=\"476\" y=\"344\" width=\"120\" height=\"22\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <text x=\"536\" y=\"359\" text-anchor=\"middle\" font-size=\"11\" fill=\"#1c2620\">Postsynaptic membrane</text>\n              </g>\n              <!-- receptor → effector -->\n              <g id=\"co-rcpt\" opacity=\"0\">\n                <line x1=\"540\" y1=\"438\" x2=\"425\" y2=\"478\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n                <rect x=\"476\" y=\"424\" width=\"120\" height=\"22\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <text x=\"536\" y=\"439\" text-anchor=\"middle\" font-size=\"11\" fill=\"#1c2620\">Receptor → effector</text>\n              </g>\n            </g>\n          </svg>\n        </div>\n        <div class=\"flowchart\">\n          <div class=\"flow-step\" data-step=\"1\"><div class=\"num\">1</div><div><div class=\"label\">Signaling cell</div><div class=\"sub\">Releases molecular signal</div></div></div>\n          <div class=\"flow-arrow\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M7 1 V13 M3 9 L7 13 L11 9\" stroke=\"#3d7a52\" stroke-width=\"1.5\" fill=\"none\"></path></svg></div>\n          <div class=\"flow-step\" data-step=\"2\"><div class=\"num\">2</div><div><div class=\"label\">Signal</div><div class=\"sub\">Neurotransmitter, hormone</div></div></div>\n          <div class=\"flow-arrow\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M7 1 V13 M3 9 L7 13 L11 9\" stroke=\"#3d7a52\" stroke-width=\"1.5\" fill=\"none\"></path></svg></div>\n          <div class=\"flow-step\" data-step=\"3\"><div class=\"num\">3</div><div><div class=\"label\">Receptor</div><div class=\"sub\">Transduces the signal</div></div></div>\n          <div class=\"flow-arrow\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M7 1 V13 M3 9 L7 13 L11 9\" stroke=\"#3d7a52\" stroke-width=\"1.5\" fill=\"none\"></path></svg></div>\n          <div class=\"flow-step\" data-step=\"4\"><div class=\"num\">4</div><div><div class=\"label\">Effector molecule</div><div class=\"sub\">Enzyme, channel, kinase</div></div></div>\n          <div class=\"flow-arrow\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M7 1 V13 M3 9 L7 13 L11 9\" stroke=\"#3d7a52\" stroke-width=\"1.5\" fill=\"none\"></path></svg></div>\n          <div class=\"flow-step\" data-step=\"5\"><div class=\"num\">5</div><div><div class=\"label\">Cellular response</div><div class=\"sub\">Electrical · biochemical · genetic</div></div></div>\n        </div>\n      </div>\n      <div class=\"notes\">\n        <button class=\"notes-toggle\" data-notes-toggle=\"\">Hide notes</button>\n        <div class=\"label\">Speaker notes</div>\n        <div class=\"body\">Let's start at the synapse, which you already know from class. A presynaptic neuron releases neurotransmitters into the synaptic cleft. Those neurotransmitters diffuse across and bind to receptor proteins embedded in the postsynaptic membrane. This binding is where everything we're going to talk about today begins. Purves describes this as a three-component system: a molecular signal that carries information, a receptor that transduces it, and an effector molecule that produces the actual cellular response. Our topic starts at a very precise location: the postsynaptic receptor. The question is not how the signal travels across the cleft — it's what happens after it arrives. That conversion is called signal transduction, and G-proteins are central to it.</div>\n      </div>\n    </section>\n\n    <!-- SLIDE 3 -->\n    <section class=\"slide s3\" data-slide=\"3\">\n      <div class=\"eyebrow\">03 · Two architectures</div>\n      <h2>Two classes of postsynaptic receptors</h2>\n      <div class=\"panels\">\n        <div class=\"panel\" id=\"panel-iono\">\n          <div class=\"ptype\">Class I</div>\n          <h3>Ionotropic</h3>\n          <svg id=\"iono-svg\" viewBox=\"0 0 600 360\" width=\"100%\" height=\"240\" preserveAspectRatio=\"xMidYMid meet\">\n            <defs>\n              <linearGradient id=\"iono-sky\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#dceaf2\"></stop><stop offset=\"100%\" stop-color=\"#c8dde8\"></stop>\n              </linearGradient>\n              <linearGradient id=\"iono-cyto\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#f5e2bd\"></stop><stop offset=\"100%\" stop-color=\"#ead2a0\"></stop>\n              </linearGradient>\n              <linearGradient id=\"iono-channel-grad\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#c9a8e0\"></stop><stop offset=\"100%\" stop-color=\"#7a5fa8\"></stop>\n              </linearGradient>\n            </defs>\n            <!-- outside cell (sky) -->\n            <rect x=\"0\" y=\"0\" width=\"600\" height=\"155\" fill=\"url(#iono-sky)\"></rect>\n            <!-- cytoplasm -->\n            <rect x=\"0\" y=\"195\" width=\"600\" height=\"165\" fill=\"url(#iono-cyto)\"></rect>\n            <!-- lipid bilayer (two rows of heads + tails) -->\n            <g id=\"iono-bilayer\">\n              <!-- upper heads -->\n              <g fill=\"#d49c4a\" stroke=\"#a8722a\" stroke-width=\"0.6\">\n                <g id=\"iono-heads-top\"></g>\n              </g>\n              <!-- lower heads -->\n              <g fill=\"#d49c4a\" stroke=\"#a8722a\" stroke-width=\"0.6\">\n                <g id=\"iono-heads-bot\"></g>\n              </g>\n            </g>\n            <!-- text labels for cell sides -->\n            <text x=\"585\" y=\"148\" text-anchor=\"end\" font-size=\"11\" fill=\"#3a4640\" font-style=\"italic\">Outside cell</text>\n            <text x=\"585\" y=\"218\" text-anchor=\"end\" font-size=\"11\" fill=\"#3a4640\" font-style=\"italic\">Inside cell</text>\n\n            <!-- LEFT channel: closed -->\n            <g id=\"iono-left\">\n              <!-- channel walls (two halves with V-shape gap at top) -->\n              <path d=\"M 130 110 L 130 200 L 150 220 L 150 130 Z\" fill=\"url(#iono-channel-grad)\" stroke=\"#3a2570\" stroke-width=\"1.2\"></path>\n              <path d=\"M 200 110 L 200 200 L 180 220 L 180 130 Z\" fill=\"url(#iono-channel-grad)\" stroke=\"#3a2570\" stroke-width=\"1.2\"></path>\n              <!-- inner closed body -->\n              <path d=\"M 150 130 L 150 220 L 165 230 L 180 220 L 180 130 L 165 105 Z\" fill=\"#5a3f8a\" stroke=\"#3a2570\" stroke-width=\"1\"></path>\n            </g>\n            <!-- ions floating around left -->\n            <g id=\"iono-loose-ions\">\n              <circle cx=\"60\" cy=\"60\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle cx=\"80\" cy=\"85\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle cx=\"100\" cy=\"55\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle cx=\"55\" cy=\"105\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle cx=\"105\" cy=\"100\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n            </g>\n            <!-- nt floating left (binding) -->\n            <circle id=\"iono-nt-left\" cx=\"165\" cy=\"80\" r=\"9\" fill=\"#3d7a52\" stroke=\"#1f4a2d\" stroke-width=\"1\"></circle>\n\n            <!-- RIGHT channel: open with bound nts -->\n            <g id=\"iono-right\">\n              <path d=\"M 380 110 L 380 200 L 400 220 L 400 130 Z\" fill=\"url(#iono-channel-grad)\" stroke=\"#3a2570\" stroke-width=\"1.2\"></path>\n              <path d=\"M 470 110 L 470 200 L 450 220 L 450 130 Z\" fill=\"url(#iono-channel-grad)\" stroke=\"#3a2570\" stroke-width=\"1.2\"></path>\n              <!-- open pore visible (gap between halves) -->\n              <line x1=\"425\" y1=\"135\" x2=\"425\" y2=\"235\" stroke=\"#3a2570\" stroke-width=\"1\" stroke-dasharray=\"2 3\" opacity=\"0.5\"></line>\n            </g>\n            <!-- bound nts on right channel -->\n            <circle id=\"iono-nt-r1\" cx=\"380\" cy=\"115\" r=\"9\" fill=\"#3d7a52\" stroke=\"#1f4a2d\" stroke-width=\"1\"></circle>\n            <circle id=\"iono-nt-r2\" cx=\"470\" cy=\"115\" r=\"9\" fill=\"#3d7a52\" stroke=\"#1f4a2d\" stroke-width=\"1\"></circle>\n            <!-- ions flowing through right -->\n            <g id=\"iono-flowing\">\n              <circle class=\"fion\" cx=\"425\" cy=\"80\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"fion\" cx=\"425\" cy=\"60\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"fion\" cx=\"410\" cy=\"100\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"fion\" cx=\"445\" cy=\"95\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n            </g>\n            <g id=\"iono-out-ions\">\n              <circle class=\"oion\" cx=\"425\" cy=\"260\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\" opacity=\"0\"></circle>\n              <circle class=\"oion\" cx=\"410\" cy=\"280\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\" opacity=\"0\"></circle>\n              <circle class=\"oion\" cx=\"440\" cy=\"295\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\" opacity=\"0\"></circle>\n            </g>\n\n            <!-- numbered callouts -->\n            <g font-size=\"11\" fill=\"#1c2620\">\n              <g id=\"iono-cb1\">\n                <rect x=\"195\" y=\"20\" width=\"120\" height=\"34\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"206\" cy=\"37\" r=\"7\" fill=\"#1c2620\"></circle>\n                <text x=\"206\" y=\"41\" text-anchor=\"middle\" font-size=\"10\" fill=\"#fff\" font-weight=\"700\">1</text>\n                <text x=\"220\" y=\"34\" font-size=\"10\">Neurotransmitter</text>\n                <text x=\"220\" y=\"47\" font-size=\"10\">binds.</text>\n                <line x1=\"200\" y1=\"55\" x2=\"170\" y2=\"73\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n              <g id=\"iono-cb2\">\n                <rect x=\"490\" y=\"100\" width=\"105\" height=\"34\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"501\" cy=\"117\" r=\"7\" fill=\"#1c2620\"></circle>\n                <text x=\"501\" y=\"121\" text-anchor=\"middle\" font-size=\"10\" fill=\"#fff\" font-weight=\"700\">2</text>\n                <text x=\"515\" y=\"114\" font-size=\"10\">Channel</text>\n                <text x=\"515\" y=\"127\" font-size=\"10\">opens.</text>\n                <line x1=\"490\" y1=\"125\" x2=\"465\" y2=\"135\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n              <g id=\"iono-cb3\">\n                <rect x=\"470\" y=\"290\" width=\"120\" height=\"34\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"481\" cy=\"307\" r=\"7\" fill=\"#1c2620\"></circle>\n                <text x=\"481\" y=\"311\" text-anchor=\"middle\" font-size=\"10\" fill=\"#fff\" font-weight=\"700\">3</text>\n                <text x=\"495\" y=\"304\" font-size=\"10\">Ions flow across</text>\n                <text x=\"495\" y=\"317\" font-size=\"10\">membrane.</text>\n                <line x1=\"470\" y1=\"307\" x2=\"445\" y2=\"297\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n            </g>\n          </svg>\n          <div class=\"speed\">Direct · Fast · Channel opens</div>\n        </div>\n\n        <div class=\"panel\" id=\"panel-meta\">\n          <div class=\"ptype\">Class II</div>\n          <h3>Metabotropic</h3>\n          <svg id=\"meta-svg\" viewBox=\"0 0 600 360\" width=\"100%\" height=\"240\" preserveAspectRatio=\"xMidYMid meet\">\n            <defs>\n              <linearGradient id=\"meta-sky\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#dceaf2\"></stop><stop offset=\"100%\" stop-color=\"#c8dde8\"></stop>\n              </linearGradient>\n              <linearGradient id=\"meta-cyto\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#f5e2bd\"></stop><stop offset=\"100%\" stop-color=\"#ead2a0\"></stop>\n              </linearGradient>\n              <linearGradient id=\"meta-rec\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#f0c89a\"></stop><stop offset=\"100%\" stop-color=\"#c89860\"></stop>\n              </linearGradient>\n              <linearGradient id=\"meta-gp\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#7ab0d8\"></stop><stop offset=\"100%\" stop-color=\"#3a78b8\"></stop>\n              </linearGradient>\n              <radialGradient id=\"meta-burst\" cx=\"50%\" cy=\"50%\" r=\"50%\">\n                <stop offset=\"0%\" stop-color=\"#ffe27a\" stop-opacity=\"0.95\"></stop>\n                <stop offset=\"60%\" stop-color=\"#ffd14a\" stop-opacity=\"0.7\"></stop>\n                <stop offset=\"100%\" stop-color=\"#ffd14a\" stop-opacity=\"0\"></stop>\n              </radialGradient>\n            </defs>\n            <rect x=\"0\" y=\"0\" width=\"600\" height=\"155\" fill=\"url(#meta-sky)\"></rect>\n            <rect x=\"0\" y=\"195\" width=\"600\" height=\"165\" fill=\"url(#meta-cyto)\"></rect>\n            <g id=\"meta-bilayer\">\n              <g fill=\"#d49c4a\" stroke=\"#a8722a\" stroke-width=\"0.6\"><g id=\"meta-heads-top\"></g></g>\n              <g fill=\"#d49c4a\" stroke=\"#a8722a\" stroke-width=\"0.6\"><g id=\"meta-heads-bot\"></g></g>\n            </g>\n            <text x=\"290\" y=\"148\" text-anchor=\"middle\" font-size=\"11\" fill=\"#3a4640\" font-style=\"italic\" id=\"meta-receptor-label\">Receptor</text>\n\n            <!-- LEFT receptor: signal binding, G-protein detached -->\n            <g id=\"meta-left\">\n              <!-- receptor: U-shape opening upward -->\n              <path d=\"M 110 110 Q 110 100 120 100 L 145 100 Q 155 100 155 115 L 155 165 Q 155 175 145 175 L 175 175 Q 185 175 185 165 L 185 115 Q 185 100 195 100 L 220 100 Q 230 100 230 110 L 230 200 L 110 200 Z\" fill=\"url(#meta-rec)\" stroke=\"#8a5a25\" stroke-width=\"1.2\"></path>\n            </g>\n            <!-- floating neurotransmitters -->\n            <circle id=\"meta-nt-far1\" cx=\"65\" cy=\"50\" r=\"9\" fill=\"#3d7a52\" stroke=\"#1f4a2d\" stroke-width=\"1\"></circle>\n            <circle id=\"meta-nt-far2\" cx=\"100\" cy=\"80\" r=\"9\" fill=\"#3d7a52\" stroke=\"#1f4a2d\" stroke-width=\"1\"></circle>\n            <circle id=\"meta-nt-binding\" cx=\"170\" cy=\"90\" r=\"9\" fill=\"#3d7a52\" stroke=\"#1f4a2d\" stroke-width=\"1\"></circle>\n\n            <!-- detached G-protein (left, below) -->\n            <g id=\"meta-gp-detached\">\n              <ellipse cx=\"240\" cy=\"265\" rx=\"22\" ry=\"14\" fill=\"url(#meta-gp)\" stroke=\"#1f4a6e\" stroke-width=\"1\" transform=\"rotate(-15 240 265)\"></ellipse>\n              <text x=\"232\" y=\"270\" font-size=\"10\" fill=\"#1c2620\" font-weight=\"700\" font-style=\"italic\">α</text>\n              <text x=\"250\" y=\"262\" font-size=\"9\" fill=\"#1c2620\" font-weight=\"700\" font-style=\"italic\">β</text>\n              <!-- arrow up to receptor -->\n              <path d=\"M 215 245 L 200 215\" stroke=\"#3a4640\" stroke-width=\"1.2\" fill=\"none\" marker-end=\"url(#meta-arrow-h)\"></path>\n            </g>\n            <defs>\n              <marker id=\"meta-arrow-h\" viewBox=\"0 0 10 10\" refX=\"8\" refY=\"5\" markerWidth=\"5\" markerHeight=\"5\" orient=\"auto\">\n                <path d=\"M0 0 L10 5 L0 10 Z\" fill=\"#3a4640\"></path>\n              </marker>\n            </defs>\n\n            <!-- RIGHT receptor: bound + activated G-protein -->\n            <g id=\"meta-right\">\n              <path d=\"M 360 110 Q 360 100 370 100 L 395 100 Q 405 100 405 115 L 405 165 Q 405 175 395 175 L 425 175 Q 435 175 435 165 L 435 115 Q 435 100 445 100 L 470 100 Q 480 100 480 110 L 480 200 L 360 200 Z\" fill=\"url(#meta-rec)\" stroke=\"#8a5a25\" stroke-width=\"1.2\"></path>\n            </g>\n            <!-- bound nt on top of right receptor -->\n            <circle id=\"meta-nt-bound\" cx=\"420\" cy=\"100\" r=\"9\" fill=\"#3d7a52\" stroke=\"#1f4a2d\" stroke-width=\"1\"></circle>\n            <!-- activated G-protein with starburst -->\n            <g id=\"meta-gp-active\">\n              <!-- starburst -->\n              <polygon id=\"meta-starburst\" points=\"420,200 432,222 458,218 442,240 458,262 432,258 420,280 408,258 382,262 398,240 382,218 408,222\" fill=\"url(#meta-burst)\" stroke=\"#e8a020\" stroke-width=\"0.8\" opacity=\"0\"></polygon>\n              <ellipse cx=\"420\" cy=\"240\" rx=\"22\" ry=\"14\" fill=\"url(#meta-gp)\" stroke=\"#1f4a6e\" stroke-width=\"1\"></ellipse>\n              <text x=\"412\" y=\"245\" font-size=\"10\" fill=\"#1c2620\" font-weight=\"700\" font-style=\"italic\">α</text>\n              <text x=\"430\" y=\"237\" font-size=\"9\" fill=\"#1c2620\" font-weight=\"700\" font-style=\"italic\">β</text>\n            </g>\n            <text x=\"320\" y=\"225\" font-size=\"10\" fill=\"#1c2620\" font-style=\"italic\">G-protein</text>\n            <line x1=\"350\" y1=\"223\" x2=\"395\" y2=\"240\" stroke=\"#3a4640\" stroke-width=\"0.8\"></line>\n\n            <!-- callouts -->\n            <g font-size=\"11\" fill=\"#1c2620\">\n              <g id=\"meta-cb1\">\n                <rect x=\"195\" y=\"20\" width=\"80\" height=\"34\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"206\" cy=\"37\" r=\"7\" fill=\"#1c2620\"></circle>\n                <text x=\"206\" y=\"41\" text-anchor=\"middle\" font-size=\"10\" fill=\"#fff\" font-weight=\"700\">1</text>\n                <text x=\"220\" y=\"34\" font-size=\"10\">Signal</text>\n                <text x=\"220\" y=\"47\" font-size=\"10\">binds.</text>\n                <line x1=\"205\" y1=\"55\" x2=\"175\" y2=\"80\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n              <g id=\"meta-cb2\">\n                <rect x=\"100\" y=\"295\" width=\"115\" height=\"34\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"111\" cy=\"312\" r=\"7\" fill=\"#1c2620\"></circle>\n                <text x=\"111\" y=\"316\" text-anchor=\"middle\" font-size=\"10\" fill=\"#fff\" font-weight=\"700\">2</text>\n                <text x=\"125\" y=\"309\" font-size=\"10\">G-protein</text>\n                <text x=\"125\" y=\"322\" font-size=\"10\">binds.</text>\n                <line x1=\"200\" y1=\"305\" x2=\"225\" y2=\"275\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n              <g id=\"meta-cb3\">\n                <rect x=\"470\" y=\"295\" width=\"115\" height=\"34\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"481\" cy=\"312\" r=\"7\" fill=\"#1c2620\"></circle>\n                <text x=\"481\" y=\"316\" text-anchor=\"middle\" font-size=\"10\" fill=\"#fff\" font-weight=\"700\">3</text>\n                <text x=\"495\" y=\"309\" font-size=\"10\">G-protein</text>\n                <text x=\"495\" y=\"322\" font-size=\"10\">activated.</text>\n                <line x1=\"470\" y1=\"305\" x2=\"445\" y2=\"265\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n            </g>\n          </svg>\n          <div class=\"speed\">Indirect · Slower · Intracellular signaling</div>\n        </div>\n      </div>\n      <div class=\"insight\" id=\"s3-insight\">Not just fast vs slow — different <em>types</em> of response.</div>\n      <div class=\"notes\">\n        <button class=\"notes-toggle\" data-notes-toggle=\"\">Hide notes</button>\n        <div class=\"label\">Speaker notes</div>\n        <div class=\"body\">Not all postsynaptic receptors work the same way. Purves distinguishes two fundamentally different classes. Ionotropic receptors have the receptor and the ion channel as part of the same protein complex. When the neurotransmitter binds, the channel opens directly, ions flow, and the membrane potential changes — fast and direct. Metabotropic receptors work differently. They don't open a channel directly; instead, they activate intracellular signaling molecules — the G-proteins — which then regulate effectors inside the cell. The deeper difference is not just fast versus slow: ionotropic receptors are useful when the cell needs a direct electrical response. Metabotropic receptors are useful when the cell needs a controlled intracellular cascade.</div>\n      </div>\n    </section>\n\n    <!-- SLIDE 4 -->\n    <section class=\"slide s4\" data-slide=\"4\">\n      <div class=\"eyebrow\">04 · Mechanism</div>\n      <h2>General mechanism of metabotropic signaling</h2>\n      <div class=\"layout\">\n        <div class=\"card\" style=\"padding:14px\">\n          <svg id=\"mech-svg\" viewBox=\"0 0 760 460\" width=\"100%\" height=\"100%\" preserveAspectRatio=\"xMidYMid meet\">\n            <defs>\n              <linearGradient id=\"m4-sky\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#dceaf2\"></stop><stop offset=\"100%\" stop-color=\"#c8dde8\"></stop>\n              </linearGradient>\n              <linearGradient id=\"m4-cyto\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#f5e2bd\"></stop><stop offset=\"100%\" stop-color=\"#ead2a0\"></stop>\n              </linearGradient>\n              <linearGradient id=\"m4-rec\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#e0867a\"></stop><stop offset=\"100%\" stop-color=\"#b85042\"></stop>\n              </linearGradient>\n              <linearGradient id=\"m4-eff\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#d99a6e\"></stop><stop offset=\"100%\" stop-color=\"#a06642\"></stop>\n              </linearGradient>\n              <linearGradient id=\"m4-chan\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#c9a8e0\"></stop><stop offset=\"100%\" stop-color=\"#7a5fa8\"></stop>\n              </linearGradient>\n              <linearGradient id=\"m4-gp\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stop-color=\"#7ab0d8\"></stop><stop offset=\"100%\" stop-color=\"#3a78b8\"></stop>\n              </linearGradient>\n              <radialGradient id=\"m4-burst\" cx=\"50%\" cy=\"50%\" r=\"50%\">\n                <stop offset=\"0%\" stop-color=\"#ffe27a\" stop-opacity=\"0.95\"></stop>\n                <stop offset=\"60%\" stop-color=\"#ffd14a\" stop-opacity=\"0.7\"></stop>\n                <stop offset=\"100%\" stop-color=\"#ffd14a\" stop-opacity=\"0\"></stop>\n              </radialGradient>\n              <marker id=\"m4-arrow-h\" viewBox=\"0 0 10 10\" refX=\"8\" refY=\"5\" markerWidth=\"5\" markerHeight=\"5\" orient=\"auto\">\n                <path d=\"M0 0 L10 5 L0 10 Z\" fill=\"#3a4640\"></path>\n              </marker>\n            </defs>\n\n            <rect x=\"0\" y=\"0\" width=\"760\" height=\"180\" fill=\"url(#m4-sky)\"></rect>\n            <rect x=\"0\" y=\"220\" width=\"760\" height=\"240\" fill=\"url(#m4-cyto)\"></rect>\n\n            <!-- bilayer heads -->\n            <g fill=\"#d49c4a\" stroke=\"#a8722a\" stroke-width=\"0.6\"><g id=\"m4-heads-top\"></g></g>\n            <g fill=\"#d49c4a\" stroke=\"#a8722a\" stroke-width=\"0.6\"><g id=\"m4-heads-bot\"></g></g>\n\n            <!-- ===== RECEPTOR (left) ===== -->\n            <g id=\"m4-receptor\">\n              <!-- U-shape opening up -->\n              <path d=\"M 130 130 Q 130 115 145 115 L 175 115 Q 188 115 188 135 L 188 175 Q 188 188 175 188 L 205 188 Q 218 188 218 175 L 218 135 Q 218 115 231 115 L 261 115 Q 276 115 276 130 L 276 230 L 130 230 Z\" fill=\"url(#m4-rec)\" stroke=\"#7a2515\" stroke-width=\"1.4\"></path>\n            </g>\n            <!-- floating neurotransmitter -->\n            <circle id=\"m4-nt-far\" cx=\"100\" cy=\"55\" r=\"9\" fill=\"#3d7a52\" stroke=\"#1f4a2d\" stroke-width=\"1\"></circle>\n            <!-- bound neurotransmitter -->\n            <circle id=\"m4-nt-bound\" cx=\"200\" cy=\"120\" r=\"9\" fill=\"#3d7a52\" stroke=\"#1f4a2d\" stroke-width=\"1\"></circle>\n\n            <!-- ===== G-protein detached (under receptor) ===== -->\n            <g id=\"m4-gp-rec\">\n              <polygon id=\"m4-burst\" points=\"220,230 232,250 256,246 240,266 256,286 232,282 220,302 208,282 184,286 200,266 184,246 208,250\" fill=\"url(#m4-burst)\" stroke=\"#e8a020\" stroke-width=\"0.8\" opacity=\"0\"></polygon>\n              <ellipse cx=\"220\" cy=\"266\" rx=\"22\" ry=\"14\" fill=\"url(#m4-gp)\" stroke=\"#1f4a6e\" stroke-width=\"1\"></ellipse>\n              <text x=\"212\" y=\"271\" font-size=\"10\" fill=\"#1c2620\" font-weight=\"700\" font-style=\"italic\">α</text>\n              <text x=\"230\" y=\"263\" font-size=\"9\" fill=\"#1c2620\" font-weight=\"700\" font-style=\"italic\">β</text>\n              <text x=\"240\" y=\"273\" font-size=\"9\" fill=\"#1c2620\" font-weight=\"700\" font-style=\"italic\">γ</text>\n            </g>\n\n            <!-- traveling alpha subunit -->\n            <g id=\"m4-alpha-travel\" opacity=\"0\">\n              <ellipse cx=\"290\" cy=\"290\" rx=\"16\" ry=\"11\" fill=\"url(#m4-gp)\" stroke=\"#1f4a6e\" stroke-width=\"1\"></ellipse>\n              <text x=\"284\" y=\"294\" font-size=\"10\" fill=\"#1c2620\" font-weight=\"700\" font-style=\"italic\">α</text>\n            </g>\n\n            <!-- ===== EFFECTOR (middle) ===== -->\n            <g id=\"m4-effector\">\n              <!-- two bumps shape -->\n              <path d=\"M 365 165 Q 365 145 380 145 Q 395 145 395 165 L 395 230 L 415 230 L 415 175 Q 415 155 430 155 Q 445 155 445 175 L 445 230 L 365 230 Z\" fill=\"url(#m4-eff)\" stroke=\"#5a3015\" stroke-width=\"1.2\"></path>\n            </g>\n            <text x=\"360\" y=\"135\" font-size=\"11\" fill=\"#1c2620\" font-style=\"italic\" text-anchor=\"end\">Effector protein</text>\n            <line x1=\"362\" y1=\"138\" x2=\"395\" y2=\"155\" stroke=\"#3a4640\" stroke-width=\"0.8\"></line>\n\n            <!-- arrow alpha -> effector -->\n            <path id=\"m4-arrow-eff\" d=\"M 250 280 Q 320 295 365 270\" stroke=\"#3a4640\" stroke-width=\"1.5\" fill=\"none\" marker-end=\"url(#m4-arrow-h)\" opacity=\"0\"></path>\n            <text x=\"335\" y=\"315\" font-size=\"11\" font-style=\"italic\" fill=\"#1c2620\" text-anchor=\"middle\" id=\"m4-msg-label\" opacity=\"0\">Intracellular</text>\n            <text x=\"335\" y=\"328\" font-size=\"11\" font-style=\"italic\" fill=\"#1c2620\" text-anchor=\"middle\" id=\"m4-msg-label2\" opacity=\"0\">messengers</text>\n\n            <!-- second messengers near effector -->\n            <g id=\"m4-messengers\">\n              <circle class=\"m4msg\" cx=\"455\" cy=\"290\" r=\"4.5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\" opacity=\"0\"></circle>\n              <circle class=\"m4msg\" cx=\"475\" cy=\"305\" r=\"4.5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\" opacity=\"0\"></circle>\n              <circle class=\"m4msg\" cx=\"495\" cy=\"290\" r=\"4.5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\" opacity=\"0\"></circle>\n              <circle class=\"m4msg\" cx=\"510\" cy=\"320\" r=\"4.5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\" opacity=\"0\"></circle>\n              <circle class=\"m4msg\" cx=\"530\" cy=\"305\" r=\"4.5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\" opacity=\"0\"></circle>\n            </g>\n            <text x=\"510\" y=\"345\" font-size=\"11\" fill=\"#1c2620\" font-style=\"italic\" id=\"m4-ions-label\" opacity=\"0\">Ions</text>\n\n            <!-- arrow messengers -> channel -->\n            <path id=\"m4-arrow-chan\" d=\"M 540 305 Q 580 290 605 245\" stroke=\"#3a4640\" stroke-width=\"1.5\" fill=\"none\" marker-end=\"url(#m4-arrow-h)\" opacity=\"0\"></path>\n\n            <!-- ===== ION CHANNEL (right) ===== -->\n            <g id=\"m4-channel\">\n              <path d=\"M 580 130 L 580 230 L 605 250 L 605 150 Z\" fill=\"url(#m4-chan)\" stroke=\"#3a2570\" stroke-width=\"1.2\"></path>\n              <path d=\"M 680 130 L 680 230 L 655 250 L 655 150 Z\" fill=\"url(#m4-chan)\" stroke=\"#3a2570\" stroke-width=\"1.2\"></path>\n              <!-- top funnel V -->\n              <path d=\"M 605 150 L 630 130 L 655 150\" fill=\"none\" stroke=\"#3a2570\" stroke-width=\"1.2\"></path>\n            </g>\n\n            <!-- floating ions outside (top right) -->\n            <g id=\"m4-ions-out\">\n              <circle class=\"m4ion\" cx=\"610\" cy=\"50\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"m4ion\" cx=\"635\" cy=\"40\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"m4ion\" cx=\"660\" cy=\"55\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"m4ion\" cx=\"600\" cy=\"80\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"m4ion\" cx=\"625\" cy=\"90\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"m4ion\" cx=\"655\" cy=\"80\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"m4ion\" cx=\"680\" cy=\"65\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n              <circle class=\"m4ion\" cx=\"685\" cy=\"100\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\"></circle>\n            </g>\n            <!-- ion flowing through channel -->\n            <circle id=\"m4-ion-flow\" cx=\"630\" cy=\"160\" r=\"5\" fill=\"#d44a3a\" stroke=\"#7a2515\" stroke-width=\"0.6\" opacity=\"0\"></circle>\n\n            <!-- \"Receptor\" label -->\n            <g id=\"m4-rec-label\" opacity=\"0\">\n              <text x=\"305\" y=\"125\" font-size=\"11\" font-style=\"italic\" fill=\"#1c2620\">Receptor</text>\n              <line x1=\"304\" y1=\"128\" x2=\"278\" y2=\"135\" stroke=\"#3a4640\" stroke-width=\"0.8\"></line>\n            </g>\n            <text x=\"105\" y=\"280\" font-size=\"11\" font-style=\"italic\" fill=\"#1c2620\" id=\"m4-gp-label\" opacity=\"0\">G-protein</text>\n\n            <!-- ===== Numbered callouts ===== -->\n            <g font-family=\"Inter, sans-serif\">\n              <!-- 1 NT binds -->\n              <g id=\"m4-cb1\" opacity=\"0\">\n                <rect x=\"200\" y=\"35\" width=\"120\" height=\"38\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"212\" cy=\"54\" r=\"8\" fill=\"#1c2620\"></circle>\n                <text x=\"212\" y=\"59\" text-anchor=\"middle\" font-size=\"11\" fill=\"#fff\" font-weight=\"700\">1</text>\n                <text x=\"226\" y=\"51\" font-size=\"11\" fill=\"#1c2620\">Neurotransmitter</text>\n                <text x=\"226\" y=\"65\" font-size=\"11\" fill=\"#1c2620\">binds.</text>\n                <line x1=\"222\" y1=\"73\" x2=\"200\" y2=\"115\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n              <!-- 2 G-protein activated -->\n              <g id=\"m4-cb2\" opacity=\"0\">\n                <rect x=\"120\" y=\"345\" width=\"135\" height=\"38\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"132\" cy=\"364\" r=\"8\" fill=\"#1c2620\"></circle>\n                <text x=\"132\" y=\"369\" text-anchor=\"middle\" font-size=\"11\" fill=\"#fff\" font-weight=\"700\">2</text>\n                <text x=\"146\" y=\"361\" font-size=\"11\" fill=\"#1c2620\">G-protein is</text>\n                <text x=\"146\" y=\"375\" font-size=\"11\" fill=\"#1c2620\">activated.</text>\n                <line x1=\"222\" y1=\"345\" x2=\"220\" y2=\"298\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n              <!-- 3 Modulate -->\n              <g id=\"m4-cb3\" opacity=\"0\">\n                <rect x=\"290\" y=\"355\" width=\"200\" height=\"50\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"302\" cy=\"374\" r=\"8\" fill=\"#1c2620\"></circle>\n                <text x=\"302\" y=\"379\" text-anchor=\"middle\" font-size=\"11\" fill=\"#fff\" font-weight=\"700\">3</text>\n                <text x=\"316\" y=\"371\" font-size=\"11\" fill=\"#1c2620\">G-protein subunits or</text>\n                <text x=\"316\" y=\"385\" font-size=\"11\" fill=\"#1c2620\">intracellular messengers</text>\n                <text x=\"316\" y=\"399\" font-size=\"11\" fill=\"#1c2620\">modulate ion channels.</text>\n                <line x1=\"488\" y1=\"370\" x2=\"555\" y2=\"280\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n              <!-- 4 Channel opens -->\n              <g id=\"m4-cb4\" opacity=\"0\">\n                <rect x=\"630\" y=\"370\" width=\"115\" height=\"38\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"642\" cy=\"389\" r=\"8\" fill=\"#1c2620\"></circle>\n                <text x=\"642\" y=\"394\" text-anchor=\"middle\" font-size=\"11\" fill=\"#fff\" font-weight=\"700\">4</text>\n                <text x=\"656\" y=\"386\" font-size=\"11\" fill=\"#1c2620\">Ion channel</text>\n                <text x=\"656\" y=\"400\" font-size=\"11\" fill=\"#1c2620\">opens.</text>\n                <line x1=\"630\" y1=\"380\" x2=\"608\" y2=\"245\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n              <!-- 5 Ions flow -->\n              <g id=\"m4-cb5\" opacity=\"0\">\n                <rect x=\"640\" y=\"155\" width=\"115\" height=\"50\" rx=\"4\" fill=\"#fff\" stroke=\"#3a4640\" stroke-width=\"1\"></rect>\n                <circle cx=\"652\" cy=\"174\" r=\"8\" fill=\"#1c2620\"></circle>\n                <text x=\"652\" y=\"179\" text-anchor=\"middle\" font-size=\"11\" fill=\"#fff\" font-weight=\"700\">5</text>\n                <text x=\"666\" y=\"171\" font-size=\"11\" fill=\"#1c2620\">Ions flow</text>\n                <text x=\"666\" y=\"185\" font-size=\"11\" fill=\"#1c2620\">across</text>\n                <text x=\"666\" y=\"199\" font-size=\"11\" fill=\"#1c2620\">membrane.</text>\n                <line x1=\"640\" y1=\"180\" x2=\"612\" y2=\"170\" stroke=\"#3a4640\" stroke-width=\"1\"></line>\n              </g>\n            </g>\n          </svg>\n        </div>\n        <div class=\"right\">\n          <div class=\"flowchart s4-flow\" id=\"s4-flow\">\n            <div class=\"flow-step\" data-step=\"1\"><div class=\"num\">1</div><div><div class=\"label\">Receptor</div><div class=\"sub\">Neurotransmitter binds</div></div></div>\n            <div class=\"flow-arrow\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M7 1 V13 M3 9 L7 13 L11 9\" stroke=\"#3d7a52\" stroke-width=\"1.5\" fill=\"none\"></path></svg></div>\n            <div class=\"flow-step\" data-step=\"2\"><div class=\"num\">2</div><div><div class=\"label\">G-protein</div><div class=\"sub\">Activated at the membrane</div></div></div>\n            <div class=\"flow-arrow\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M7 1 V13 M3 9 L7 13 L11 9\" stroke=\"#3d7a52\" stroke-width=\"1.5\" fill=\"none\"></path></svg></div>\n            <div class=\"flow-step\" data-step=\"3\"><div class=\"num\">3</div><div><div class=\"label\">Effector</div><div class=\"sub\">Enzyme or channel target</div></div></div>\n            <div class=\"flow-arrow\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M7 1 V13 M3 9 L7 13 L11 9\" stroke=\"#3d7a52\" stroke-width=\"1.5\" fill=\"none\"></path></svg></div>\n            <div class=\"flow-step\" data-step=\"4\"><div class=\"num\">4</div><div><div class=\"label\">Second messenger</div><div class=\"sub\">Signal spreads inside</div></div></div>\n            <div class=\"flow-arrow\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M7 1 V13 M3 9 L7 13 L11 9\" stroke=\"#3d7a52\" stroke-width=\"1.5\" fill=\"none\"></path></svg></div>\n            <div class=\"flow-step\" data-step=\"5\"><div class=\"num\">5</div><div><div class=\"label\">Response</div><div class=\"sub\">Ion flow or cellular change</div></div></div>\n          </div>\n          <div class=\"delegation\" id=\"s4-deleg\">\n            <div class=\"lbl\">Key concept</div>\n            <div class=\"word\">DELEGATION</div>\n            <div class=\"desc\">The receptor doesn't act — it hands off responsibility, step by step.</div>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\">\n        <button class=\"notes-toggle\" data-notes-toggle=\"\">Hide notes</button>\n        <div class=\"label\">Speaker notes</div>\n        <div class=\"body\">When a neurotransmitter binds a metabotropic receptor, the receptor undergoes a conformational change on its intracellular side. This allows it to interact with a G-protein sitting at the inner face of the membrane. The G-protein then activates a downstream effector, typically an enzyme, which produces second messengers. Those second messengers propagate the signal further, changing the activity of ion channels, protein kinases, and other effector proteins inside the cell. The key concept on this slide is delegation. The receptor does not directly create the response — it hands off responsibility to the G-protein, which hands off to an enzyme, which produces second messengers, which finally act on the cell. G-proteins are the coupling step. They are the bridge between the receptor at the membrane and the response happening inside.</div>\n      </div>\n    </section>\n\n    <!-- SLIDE 5 -->\n    <section class=\"slide s5\" data-slide=\"5\">\n      <div class=\"eyebrow\">05 · The molecular cycle</div>\n      <h2>The G-protein cycle</h2>\n      <div class=\"layout\">\n        <div class=\"cycle-card\">\n          <svg id=\"cycle-svg\" viewBox=\"0 0 600 460\" width=\"100%\" height=\"100%\">\n            <!-- outer ring -->\n            <circle cx=\"300\" cy=\"230\" r=\"170\" fill=\"none\" stroke=\"#d8d6cc\" stroke-width=\"1.5\" stroke-dasharray=\"4 6\"></circle>\n            <!-- 4 phase dots -->\n            <g font-size=\"10\" fill=\"#5d6b62\" letter-spacing=\"1.5\">\n              <text x=\"300\" y=\"50\" text-anchor=\"middle\">1 · RESTING (OFF)</text>\n              <text x=\"490\" y=\"234\" text-anchor=\"middle\">2 · ACTIVATION (ON)</text>\n              <text x=\"300\" y=\"425\" text-anchor=\"middle\">3 · DISSOCIATION</text>\n              <text x=\"110\" y=\"234\" text-anchor=\"middle\">4 · HYDROLYSIS · RESET</text>\n            </g>\n            <!-- center cluster: trimer that morphs -->\n            <g id=\"trimer\">\n              <!-- alpha -->\n              <g id=\"c-alpha\">\n                <circle cx=\"300\" cy=\"230\" r=\"32\" fill=\"#caa24a\" stroke=\"#2d5a3d\" stroke-width=\"1.5\"></circle>\n                <text x=\"300\" y=\"236\" text-anchor=\"middle\" font-size=\"16\" fill=\"#1c2620\" font-weight=\"700\">α</text>\n              </g>\n              <!-- beta -->\n              <g id=\"c-beta\">\n                <circle cx=\"346\" cy=\"246\" r=\"22\" fill=\"#a3b5a8\" stroke=\"#2d5a3d\" stroke-width=\"1.5\"></circle>\n                <text x=\"346\" y=\"251\" text-anchor=\"middle\" font-size=\"12\" fill=\"#1c2620\" font-weight=\"700\">β</text>\n              </g>\n              <!-- gamma -->\n              <g id=\"c-gamma\">\n                <circle cx=\"370\" cy=\"226\" r=\"16\" fill=\"#c4cfc7\" stroke=\"#2d5a3d\" stroke-width=\"1.5\"></circle>\n                <text x=\"370\" y=\"230\" text-anchor=\"middle\" font-size=\"10\" fill=\"#1c2620\" font-weight=\"700\">γ</text>\n              </g>\n              <!-- nucleotide -->\n              <g id=\"c-nuc\">\n                <rect id=\"c-nuc-box\" x=\"278\" y=\"218\" width=\"44\" height=\"22\" rx=\"3\" fill=\"#fff\" stroke=\"#2d5a3d\" stroke-width=\"1.2\"></rect>\n                <text id=\"c-nuc-text\" x=\"300\" y=\"234\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"700\" fill=\"#5d6b62\">GDP</text>\n              </g>\n            </g>\n            <!-- arrows around the ring -->\n            <g fill=\"none\" stroke=\"#3d7a52\" stroke-width=\"1.5\" marker-end=\"url(#cyc-arrow)\">\n              <path d=\"M 380 90 Q 460 130 470 200\"></path>\n              <path d=\"M 470 270 Q 460 340 380 380\"></path>\n              <path d=\"M 220 380 Q 140 340 130 270\"></path>\n              <path d=\"M 130 200 Q 140 130 220 90\"></path>\n            </g>\n            <defs>\n              <marker id=\"cyc-arrow\" viewBox=\"0 0 10 10\" refX=\"8\" refY=\"5\" markerWidth=\"6\" markerHeight=\"6\" orient=\"auto\">\n                <path d=\"M0 0 L10 5 L0 10 Z\" fill=\"#3d7a52\"></path>\n              </marker>\n            </defs>\n          </svg>\n        </div>\n        <div class=\"state-list\">\n          <div class=\"state\" data-state=\"1\">\n            <div class=\"tag off\">GDP · Off</div>\n            <div class=\"desc\">Resting trimer. Alpha holds GDP.</div>\n          </div>\n          <div class=\"state\" data-state=\"2\">\n            <div class=\"tag on\">GTP · On</div>\n            <div class=\"desc\">Receptor triggers GDP–GTP exchange.</div>\n          </div>\n          <div class=\"state\" data-state=\"3\">\n            <div class=\"tag off\">Hydrolysis · Off again</div>\n            <div class=\"desc\">α reassembles with βγ. Reset.</div>\n          </div>\n          <div class=\"insight\" id=\"s5-insight\" style=\"margin:0\">A controlled timer — not a permanent switch.</div>\n        </div>\n      </div>\n      <div class=\"notes\">\n        <button class=\"notes-toggle\" data-notes-toggle=\"\">Hide notes</button>\n        <div class=\"label\">Speaker notes</div>\n        <div class=\"body\">Heterotrimeric G-proteins have three subunits: alpha, beta, and gamma. In the resting state, GDP is bound to the alpha subunit — GDP means off. When the receptor is activated, it triggers the exchange of GDP for GTP on the alpha subunit. GTP means on. Once active, the alpha-GTP subunit dissociates from the beta-gamma complex, and both go on to regulate downstream effectors. But the signal doesn't stay on forever. The alpha subunit hydrolyzes GTP back to GDP on its own — off again. The system resets. The G-protein is a controlled timer: it turns on briefly, acts, and turns itself off. A signal that can't switch off is a signal that can't be regulated.</div>\n      </div>\n    </section>\n\n    <!-- SLIDE 6 -->\n    <section class=\"slide s6\" data-slide=\"6\">\n      <div class=\"eyebrow\">06 · Three pathways</div>\n      <h2>Three main G-protein pathways</h2>\n      <div class=\"columns\">\n        <!-- Gs -->\n        <div class=\"pcol gs\" data-col=\"gs\">\n          <div class=\"header\"><span class=\"dot\"></span><span class=\"name\" style=\"color:var(--accent-blue)\">Gs pathway</span></div>\n          <div class=\"step\"><span class=\"k\">Signal</span><span class=\"v\">Norepinephrine</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">Receptor</span><span class=\"v\">β-adrenergic</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">G-protein</span><span class=\"v\">Gs</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">Effector</span><span class=\"v\">Adenylyl cyclase</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\" style=\"position:relative;\">\n            <span class=\"k\">2nd msg</span><span class=\"v\">cAMP</span>\n            <svg width=\"60\" height=\"22\" viewBox=\"0 0 60 22\" style=\"margin-left:auto\" id=\"gs-camp\">\n              <circle class=\"d\" cx=\"6\" cy=\"11\" r=\"3\" fill=\"#2c5d87\" opacity=\"0\"></circle>\n              <circle class=\"d\" cx=\"16\" cy=\"11\" r=\"3\" fill=\"#2c5d87\" opacity=\"0\"></circle>\n              <circle class=\"d\" cx=\"26\" cy=\"11\" r=\"3\" fill=\"#2c5d87\" opacity=\"0\"></circle>\n              <circle class=\"d\" cx=\"36\" cy=\"11\" r=\"3\" fill=\"#2c5d87\" opacity=\"0\"></circle>\n              <circle class=\"d\" cx=\"46\" cy=\"11\" r=\"3\" fill=\"#2c5d87\" opacity=\"0\"></circle>\n              <circle class=\"d\" cx=\"56\" cy=\"11\" r=\"3\" fill=\"#2c5d87\" opacity=\"0\"></circle>\n            </svg>\n          </div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">Kinase</span><span class=\"v\">PKA ↑</span></div>\n          <div class=\"outcome\">↑ Protein phosphorylation</div>\n        </div>\n        <!-- Gi -->\n        <div class=\"pcol gi\" data-col=\"gi\">\n          <div class=\"header\"><span class=\"dot\"></span><span class=\"name\" style=\"color:var(--accent-red)\">Gi pathway</span></div>\n          <div class=\"step\"><span class=\"k\">Signal</span><span class=\"v\">Dopamine</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">Receptor</span><span class=\"v\">D2</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">G-protein</span><span class=\"v\">Gi</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\">\n            <span class=\"k\">Effector</span><span class=\"v\">Adenylyl cyclase</span>\n            <span style=\"margin-left:auto; color:var(--accent-red); font-weight:800; font-size:16px\" id=\"gi-minus\">⊖</span>\n          </div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\" style=\"position:relative;\">\n            <span class=\"k\">2nd msg</span><span class=\"v\">cAMP ↓</span>\n            <svg width=\"60\" height=\"22\" viewBox=\"0 0 60 22\" style=\"margin-left:auto\" id=\"gi-camp\">\n              <circle class=\"d\" cx=\"6\" cy=\"11\" r=\"3\" fill=\"#b45341\"></circle>\n              <circle class=\"d\" cx=\"16\" cy=\"11\" r=\"3\" fill=\"#b45341\"></circle>\n              <circle class=\"d\" cx=\"26\" cy=\"11\" r=\"3\" fill=\"#b45341\"></circle>\n              <circle class=\"d\" cx=\"36\" cy=\"11\" r=\"3\" fill=\"#b45341\"></circle>\n              <circle class=\"d\" cx=\"46\" cy=\"11\" r=\"3\" fill=\"#b45341\"></circle>\n              <circle class=\"d\" cx=\"56\" cy=\"11\" r=\"3\" fill=\"#b45341\"></circle>\n            </svg>\n          </div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">Kinase</span><span class=\"v\">PKA ↓</span></div>\n          <div class=\"outcome\">↓ Protein phosphorylation</div>\n        </div>\n        <!-- Gq -->\n        <div class=\"pcol gq\" data-col=\"gq\">\n          <div class=\"header\"><span class=\"dot\"></span><span class=\"name\" style=\"color:#3d7a52\">Gq pathway</span></div>\n          <div class=\"step\"><span class=\"k\">Signal</span><span class=\"v\">Glutamate</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">Receptor</span><span class=\"v\">mGluR</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">G-protein</span><span class=\"v\">Gq</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">Effector</span><span class=\"v\">Phospholipase C</span></div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\" style=\"gap:14px\" id=\"gq-split\">\n            <div style=\"display:flex;flex-direction:column;align-items:flex-start\">\n              <span class=\"k\">2nd msg</span><span class=\"v\">IP₃</span>\n              <span style=\"font-size:11px;color:var(--muted)\">→ Ca²⁺ release</span>\n            </div>\n            <div style=\"width:1px; height:36px; background:var(--hair); margin:0 4px\"></div>\n            <div style=\"display:flex;flex-direction:column;align-items:flex-start\">\n              <span class=\"k\">2nd msg</span><span class=\"v\">DAG</span>\n              <span style=\"font-size:11px;color:var(--muted)\">→ PKC activation</span>\n            </div>\n          </div>\n          <div class=\"arrow\">↓</div>\n          <div class=\"step\"><span class=\"k\">Kinase</span><span class=\"v\">PKC ↑</span></div>\n          <div class=\"outcome\">↑ Phosphorylation (different route)</div>\n        </div>\n      </div>\n      <div class=\"footer-line\" id=\"s6-footer\">Not a single line — a routing system.</div>\n      <div class=\"notes\">\n        <button class=\"notes-toggle\" data-notes-toggle=\"\">Hide notes</button>\n        <div class=\"label\">Speaker notes</div>\n        <div class=\"body\"><strong>Gs:</strong> Once the G-protein is active, which effector it targets depends on which type is involved. Gs activates adenylyl cyclase, which converts ATP into cAMP — a major second messenger. cAMP then activates PKA, which phosphorylates target proteins and increases cellular activity. One receptor, one binding event, thousands of cAMP molecules produced downstream. <strong>Gi and Gq:</strong> Gi inhibits adenylyl cyclase, so cAMP levels drop and PKA activity decreases — a suppression of that branch. Gq takes a completely different route. It activates phospholipase C, which produces two second messengers at once: IP₃ and DAG. IP₃ triggers calcium release; DAG activates PKC. The takeaway: G-protein signaling is not a single line — it's a routing system.</div>\n      </div>\n    </section>\n\n    <!-- SLIDE 7 -->\n    <section class=\"slide s7\" data-slide=\"7\">\n      <div class=\"eyebrow\">07 · Why this design</div>\n      <h2>Why use this pathway?</h2>\n      <div class=\"why\">\n        <div class=\"why-card\" data-why=\"amp\">\n          <div class=\"label\">Advantage 01</div>\n          <div class=\"name\">Amplification</div>\n          <div class=\"desc\">1 receptor → many G-proteins → many enzymes → many second messengers.</div>\n          <div class=\"visual\">\n            <svg viewBox=\"0 0 280 110\" width=\"100%\" height=\"110\" id=\"amp-svg\">\n              <!-- 1 receptor -->\n              <circle cx=\"20\" cy=\"55\" r=\"6\" fill=\"#2d5a3d\"></circle>\n              <!-- spreading dots cloud -->\n              <g id=\"amp-dots\"></g>\n            </svg>\n          </div>\n          <div class=\"counter\" id=\"amp-counter\">×0</div>\n        </div>\n        <div class=\"why-card\" data-why=\"div\">\n          <div class=\"label\">Advantage 02</div>\n          <div class=\"name\">Diversity</div>\n          <div class=\"desc\">One receptor family routes to multiple, distinct outcomes.</div>\n          <div class=\"visual\">\n            <svg viewBox=\"0 0 280 130\" width=\"100%\" height=\"130\" id=\"div-svg\">\n              <circle cx=\"40\" cy=\"65\" r=\"9\" fill=\"#2d5a3d\"></circle>\n              <text x=\"40\" y=\"100\" text-anchor=\"middle\" font-size=\"9\" fill=\"#5d6b62\">RECEPTOR</text>\n              <path id=\"div-p1\" d=\"M 50 60 Q 130 30 240 30\" stroke=\"#2c5d87\" stroke-width=\"2.5\" fill=\"none\" stroke-dasharray=\"280\" stroke-dashoffset=\"280\" marker-end=\"url(#div-h1)\"></path>\n              <path id=\"div-p2\" d=\"M 50 65 Q 130 65 240 65\" stroke=\"#b45341\" stroke-width=\"2.5\" fill=\"none\" stroke-dasharray=\"280\" stroke-dashoffset=\"280\" marker-end=\"url(#div-h2)\"></path>\n              <path id=\"div-p3\" d=\"M 50 70 Q 130 100 240 100\" stroke=\"#3d7a52\" stroke-width=\"2.5\" fill=\"none\" stroke-dasharray=\"280\" stroke-dashoffset=\"280\" marker-end=\"url(#div-h3)\"></path>\n              <defs>\n                <marker id=\"div-h1\" viewBox=\"0 0 10 10\" refX=\"8\" refY=\"5\" markerWidth=\"5\" markerHeight=\"5\" orient=\"auto\"><path d=\"M0 0 L10 5 L0 10 Z\" fill=\"#2c5d87\"></path></marker>\n                <marker id=\"div-h2\" viewBox=\"0 0 10 10\" refX=\"8\" refY=\"5\" markerWidth=\"5\" markerHeight=\"5\" orient=\"auto\"><path d=\"M0 0 L10 5 L0 10 Z\" fill=\"#b45341\"></path></marker>\n                <marker id=\"div-h3\" viewBox=\"0 0 10 10\" refX=\"8\" refY=\"5\" markerWidth=\"5\" markerHeight=\"5\" orient=\"auto\"><path d=\"M0 0 L10 5 L0 10 Z\" fill=\"#3d7a52\"></path></marker>\n              </defs>\n              <text x=\"248\" y=\"33\" font-size=\"10\" fill=\"#2c5d87\" font-weight=\"700\">cAMP ↑</text>\n              <text x=\"248\" y=\"68\" font-size=\"10\" fill=\"#b45341\" font-weight=\"700\">cAMP ↓</text>\n              <text x=\"248\" y=\"103\" font-size=\"10\" fill=\"#3d7a52\" font-weight=\"700\">Ca²⁺ / PKC</text>\n            </svg>\n          </div>\n          <div class=\"counter\" style=\"font-size:18px; color:var(--muted); font-weight:600\">3 distinct routes</div>\n        </div>\n        <div class=\"why-card\" data-why=\"mod\">\n          <div class=\"label\">Advantage 03</div>\n          <div class=\"name\">Modulation</div>\n          <div class=\"desc\">Slower, but adjustable, sustained, and able to reach the nucleus.</div>\n          <div class=\"visual\">\n            <svg viewBox=\"0 0 280 130\" width=\"100%\" height=\"130\" id=\"mod-svg\">\n              <line x1=\"20\" y1=\"100\" x2=\"260\" y2=\"100\" stroke=\"#d8d6cc\" stroke-width=\"1\"></line>\n              <line x1=\"20\" y1=\"20\" x2=\"20\" y2=\"100\" stroke=\"#d8d6cc\" stroke-width=\"1\"></line>\n              <text x=\"20\" y=\"120\" font-size=\"9\" fill=\"#5d6b62\">time</text>\n              <!-- ionotropic spike -->\n              <path id=\"mod-spike\" d=\"M 20 100 L 50 100 L 60 30 L 70 100 L 260 100\" stroke=\"#2c5d87\" stroke-width=\"2\" fill=\"none\" stroke-dasharray=\"400\" stroke-dashoffset=\"400\"></path>\n              <text x=\"80\" y=\"40\" font-size=\"10\" fill=\"#2c5d87\" font-weight=\"700\">ionotropic</text>\n              <!-- metabotropic sustained -->\n              <path id=\"mod-curve\" d=\"M 20 100 C 50 100 70 60 110 55 C 160 50 200 60 260 70\" stroke=\"#3d7a52\" stroke-width=\"2\" fill=\"none\" stroke-dasharray=\"400\" stroke-dashoffset=\"400\"></path>\n              <text x=\"170\" y=\"50\" font-size=\"10\" fill=\"#3d7a52\" font-weight=\"700\">metabotropic</text>\n            </svg>\n          </div>\n          <div class=\"counter\" style=\"font-size:18px; color:var(--muted); font-weight:600\">seconds → hours</div>\n        </div>\n      </div>\n      <div class=\"closing\">\n        <div class=\"echo\" id=\"s7-echo\">\"How do G-proteins convert receptor activation into a cellular response?\"</div>\n        <div class=\"lines\" id=\"s7-lines\">\n          <div class=\"line\">Cells don't use G-proteins because they're <em>better</em>.</div>\n          <div class=\"line\">They use them because they're <em>complementary</em>.</div>\n        </div>\n      </div>\n      <div class=\"notes\">\n        <button class=\"notes-toggle\" data-notes-toggle=\"\">Hide notes</button>\n        <div class=\"label\">Speaker notes</div>\n        <div class=\"body\">Three reasons the cell uses G-proteins. First, amplification: one receptor activates multiple G-proteins, each activates an enzyme, each enzyme produces many second messengers. One norepinephrine molecule can lead to tens of thousands of phosphate transfers. Second, diversity: Gs, Gi, and Gq each lead to completely different outputs. Third, modulation: G-protein cascades are slower but adjustable, sustained, and can reach the nucleus to alter gene expression for hours or days. Cells don't use G-proteins because they're always better than ionotropic receptors. They use them because they're complementary. When the cell needs more control, more possible outputs, more flexibility, it uses G-proteins. That's how receptor activation is converted into a cellular response.</div>\n      </div>\n    </section>\n\n  </div>\n</div>\n\n<!-- chrome -->\n<div class=\"chrome\">\n  <div class=\"title\">G-Proteins · Cellular Signal Transduction</div>\n  <div></div>\n</div>\n<div class=\"nav\">\n  <button id=\"prev\" aria-label=\"Previous slide\" title=\"Previous (←)\">\n    <svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M9 2 L4 7 L9 12\" stroke=\"currentColor\" stroke-width=\"1.6\" fill=\"none\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg>\n  </button>\n  <div class=\"count\"><span id=\"cur\">1</span> / <span id=\"tot\">7</span></div>\n  <button id=\"next\" aria-label=\"Next slide\" title=\"Next (→)\">\n    <svg width=\"14\" height=\"14\" viewBox=\"0 0 14 14\"><path d=\"M5 2 L10 7 L5 12\" stroke=\"currentColor\" stroke-width=\"1.6\" fill=\"none\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg>\n  </button>\n</div>";
